import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as i,e as t}from"./app-f1812a7b.js";const r={},n=t(`<h1 id="生产tomcat线程阻塞问题分析" tabindex="-1"><a class="header-anchor" href="#生产tomcat线程阻塞问题分析" aria-hidden="true">#</a> 生产tomcat线程阻塞问题分析</h1><h2 id="现象" tabindex="-1"><a class="header-anchor" href="#现象" aria-hidden="true">#</a> 现象</h2><p>当大量的请求到服务，过一会，服务无法响应请求，k8s配置了健康检查，服务被k8s重启</p><h2 id="分析" tabindex="-1"><a class="header-anchor" href="#分析" aria-hidden="true">#</a> 分析</h2><p>让运维的同学把thread和heap dump了下来，打开一看，全部tomcat的线程阻塞在Druid连接池上</p><h3 id="线程情况" tabindex="-1"><a class="header-anchor" href="#线程情况" aria-hidden="true">#</a> 线程情况</h3><figure><img src="https://cdn.dhbin.cn/202303291704461.png" alt="image-20230329092255788_1" tabindex="0" loading="lazy"><figcaption>image-20230329092255788_1</figcaption></figure><p>所有的tomcat线程堵塞在<code>com.alibaba.druid.pool.DruidDataSource.takeLast</code>，该方法是从Druid的连接池取出连接，当线程池没有空闲的时候，一直阻塞等待。</p><h3 id="堆文件分析" tabindex="-1"><a class="header-anchor" href="#堆文件分析" aria-hidden="true">#</a> 堆文件分析</h3><figure><img src="https://cdn.dhbin.cn/202303291703621.png" alt="heap" tabindex="0" loading="lazy"><figcaption>heap</figcaption></figure><ul><li>notEmptyWaitThreadPeak：当前等待连接池的线程数</li><li>poolingCount：连接池中的连接数</li><li>maxActive：连接池的最大容量</li><li>activeCount：当前活跃（在执行sql的连接）数</li></ul><p>通过上图知道在一个容量为8的连接池中，有200个线程在等待一个poolingCount为0的连接池，刚好对应上tomcat的连接数</p><h2 id="解决" tabindex="-1"><a class="header-anchor" href="#解决" aria-hidden="true">#</a> 解决</h2><p>项目使用了ShardingSphere做分表分库，在配置ShardingSphere时，没有对每个数据库配置连接池大小，使用了默认配置，默认maxActive最大为8，当有慢sql阻塞的时候，很容易就出现整个服务阻塞，应当增大连接池的大小</p><p>项目中配置了<code>spring.datasource.druid.max-active</code>大小，但是shardingsphere不兼容该配置，需要像一下方式配置</p><div class="language-properties line-numbers-mode" data-ext="properties"><pre class="language-properties"><code><span class="token key attr-name">spring.shardingsphere.datasource.&lt;datasource-name&gt;.max-active</span> <span class="token punctuation">=</span> <span class="token value attr-value">xxx</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,16),d=[n];function c(s,o){return e(),i("div",null,d)}const l=a(r,[["render",c],["__file","生产tomcat线程阻塞问题分析.html.vue"]]);export{l as default};
